package main

import (
	"flag"
	"os"

	"k8s.io/client-go/kubernetes"
	"k8s.io/client-go/rest"
	"k8s.io/klog/v2"

	"github.com/volcano-sh/agentcube/pkg/router"
	"github.com/volcano-sh/agentcube/pkg/store"
)

func main() {
	port := flag.String("port", "8080", "The port to listen on")
	enableTLS := flag.Bool("enable-tls", false, "Enable TLS")
	tlsCert := flag.String("tls-cert", "", "TLS certificate file")
	tlsKey := flag.String("tls-key", "", "TLS key file")
	debug := flag.Bool("debug", false, "Enable debug mode")
	maxConcurrent := flag.Int("max-concurrent-requests", 1000, "Maximum concurrent requests")

	klog.InitFlags(nil)
	flag.Parse()

	config := &router.Config{
		Port:                  *port,
		Debug:                 *debug,
		EnableTLS:             *enableTLS,
		TLSCert:               *tlsCert,
		TLSKey:                *tlsKey,
		MaxConcurrentRequests: *maxConcurrent,
	}

	storeClient := store.Storage()
	if err := storeClient.Ping(nil); err != nil {
		klog.Fatalf("Failed to connect to store: %v", err)
	}

	var clientset kubernetes.Interface
	restConfig, err := rest.InClusterConfig()
	if err != nil {
		klog.Warningf("Failed to get in-cluster config: %v", err)
	} else {
		clientset, err = kubernetes.NewForConfig(restConfig)
		if err != nil {
			klog.Warningf("Failed to create Kubernetes client: %v", err)
		}
	}

	server, err := router.NewServer(config, storeClient, clientset)
	if err != nil {
		klog.Fatalf("Failed to create server: %v", err)
	}

	if err := server.Run(); err != nil {
		klog.Fatalf("Server failed: %v", err)
	}
}

