from typing import Optional

import requests

from ..utils.http import create_session
from ..utils.utils import read_token_from_file


class ControlPlaneClient:
    SA_TOKEN_PATH = "/var/run/secrets/kubernetes.io/serviceaccount/token"

    def __init__(
        self,
        workload_manager_url: Optional[str] = None,
        auth_token: Optional[str] = None,
        timeout: int = 120,
        connect_timeout: float = 5.0,
        pool_connections: int = 10,
        pool_maxsize: int = 10,
    ):
        self.timeout = timeout
        self.connect_timeout = connect_timeout

        self.base_url = workload_manager_url or os.environ.get("WORKLOAD_MANAGER_URL")
        if not self.base_url:
            raise ValueError("workload_manager_url is required (or set WORKLOAD_MANAGER_URL environment variable)")

        self._token = auth_token or self._get_default_token()
        self._session = create_session(pool_connections, pool_maxsize)
        self._logger = logging.getLogger("agentcube.control_plane")

    def _get_default_token(self) -> Optional[str]:
        token = read_token_from_file(self.SA_TOKEN_PATH)
        return token

    def _get_headers(self) -> dict:
        headers = {"Content-Type": "application/json"}
        if self._token:
            headers["Authorization"] = f"Bearer {self._token}"
        return headers

    def create_session(
        self,
        name: str,
        namespace: str = "default",
        metadata: Optional[dict] = None,
        ttl: Optional[str] = None,
    ) -> str:
        body = {"name": name, "namespace": namespace}
        if metadata:
            body["metadata"] = metadata
        if ttl:
            body["ttl"] = ttl

        resp = self._session.post(
            f"{self.base_url}/v1/code-interpreter",
            json=body,
            headers=self._get_headers(),
            timeout=(self.connect_timeout, self.timeout),
        )
        resp.raise_for_status()

        data = resp.json()
        session_id = data.get("sessionId")
        if not session_id:
            raise ValueError("Response missing sessionId")
        return session_id

    def delete_session(self, session_id: str) -> bool:
        try:
            resp = self._session.delete(
                f"{self.base_url}/v1/code-interpreter/sessions/{session_id}",
                headers=self._get_headers(),
                timeout=(self.connect_timeout, self.timeout),
            )
            if resp.status_code == 404:
                return True
            resp.raise_for_status()
            return True
        except Exception as e:
            self._logger.warning(f"Failed to delete session {session_id}: {e}")
            return False

    def close(self):
        if self._session:
            self._session.close()
            self._session = None

import base64
import os
import logging
from typing import Optional
from urllib.parse import urljoin

import requests

from ..utils.http import create_session
from ..exceptions import CommandExecutionError


class CodeInterpreterDataPlaneClient:
    SESSION_HEADER = "x-agentcube-session-id"

    def __init__(
        self,
        session_id: str,
        router_url: str,
        namespace: str = "default",
        cr_name: Optional[str] = None,
        base_url: Optional[str] = None,
        timeout: int = 120,
        connect_timeout: float = 5.0,
        pool_connections: int = 10,
        pool_maxsize: int = 10,
    ):
        self.session_id = session_id
        self.timeout = timeout
        self.connect_timeout = connect_timeout

        if base_url:
            self.base_url = base_url
        else:
            self.base_url = urljoin(
                router_url.rstrip("/") + "/",
                f"v1/namespaces/{namespace}/code-interpreters/{cr_name}/invocations/",
            )

        self._session = create_session(pool_connections, pool_maxsize)
        self._logger = logging.getLogger("agentcube.code_interpreter_data_plane")

    def _get_headers(self) -> dict:
        return {
            "Content-Type": "application/json",
            self.SESSION_HEADER: self.session_id,
        }

    def execute_command(self, command: list, timeout: int = 60) -> dict:
        body = {"command": command, "timeout": f"{timeout}s"}

        resp = self._session.post(
            f"{self.base_url}api/execute",
            json=body,
            headers=self._get_headers(),
            timeout=(self.connect_timeout, timeout + 2.0),
        )
        resp.raise_for_status()
        return resp.json()

    def write_file(self, content: str, remote_path: str, mode: str = "0644"):
        encoded_content = base64.b64encode(content.encode()).decode()
        body = {"path": remote_path, "content": encoded_content, "mode": mode}

        resp = self._session.post(
            f"{self.base_url}api/files",
            json=body,
            headers=self._get_headers(),
            timeout=(self.connect_timeout, self.timeout),
        )
        resp.raise_for_status()
        return resp.json()

    def upload_file(self, local_path: str, remote_path: str):
        with open(local_path, "rb") as f:
            files = {"file": (os.path.basename(local_path), f)}
            data = {"path": remote_path}
            headers = {self.SESSION_HEADER: self.session_id}

            resp = self._session.post(
                f"{self.base_url}api/files",
                files=files,
                data=data,
                headers=headers,
                timeout=(self.connect_timeout, self.timeout),
            )
        resp.raise_for_status()
        return resp.json()

    def download_file(self, remote_path: str, local_path: str):
        headers = {self.SESSION_HEADER: self.session_id}

        resp = self._session.get(
            f"{self.base_url}api/files/{remote_path}",
            headers=headers,
            stream=True,
            timeout=(self.connect_timeout, self.timeout),
        )
        resp.raise_for_status()

        with open(local_path, "wb") as f:
            for chunk in resp.iter_content(chunk_size=8192):
                f.write(chunk)

    def list_files(self, path: str = "/") -> list:
        headers = {self.SESSION_HEADER: self.session_id}

        resp = self._session.get(
            f"{self.base_url}api/files",
            params={"path": path},
            headers=headers,
            timeout=(self.connect_timeout, self.timeout),
        )
        resp.raise_for_status()
        return resp.json().get("files", [])

    def close(self):
        if self._session:
            self._session.close()
            self._session = None

def read_token_from_file(file_path: str) -> str:
    try:
        with open(file_path, "r") as f:
            return f.read().strip()
    except FileNotFoundError:
        return ""

