import os
from typing import Optional

import yaml
from pydantic import BaseModel, field_validator


class AgentMetadata(BaseModel):
    agent_name: str
    language: str = "python"
    entrypoint: Optional[str] = None
    port: int = 8080
    build_mode: str = "local"
    requirements_file: Optional[str] = None
    description: Optional[str] = None
    workload_manager_url: Optional[str] = ""
    router_url: Optional[str] = ""
    readiness_probe_path: Optional[str] = ""
    readiness_probe_port: int = 8080
    registry_url: Optional[str] = ""
    registry_username: Optional[str] = ""
    registry_password: Optional[str] = ""
    agent_endpoint: Optional[str] = ""
    version: str = "0.1.0"
    session_id: Optional[str] = None
    image_url: Optional[str] = None

    @field_validator("language")
    @classmethod
    def validate_language(cls, v):
        if v.lower() not in ("python", "java"):
            raise ValueError(f"Unsupported language: {v}")
        return v.lower()

    @field_validator("build_mode")
    @classmethod
    def validate_build_mode(cls, v):
        if v.lower() not in ("local", "cloud"):
            raise ValueError(f"Unsupported build_mode: {v}")
        return v.lower()

    @field_validator("port")
    @classmethod
    def validate_port(cls, v):
        if not 1 <= v <= 65535:
            raise ValueError(f"Port must be between 1 and 65535, got {v}")
        return v


def load_metadata(workspace_path: str) -> AgentMetadata:
    metadata_files = ["agent_metadata.yaml", "agent.yaml", "metadata.yaml"]
    for filename in metadata_files:
        filepath = os.path.join(workspace_path, filename)
        if os.path.exists(filepath):
            with open(filepath, "r") as f:
                data = yaml.safe_load(f) or {}
            return AgentMetadata(**data)
    raise FileNotFoundError(f"No metadata file found in {workspace_path}")


def save_metadata(workspace_path: str, metadata: AgentMetadata) -> str:
    filepath = os.path.join(workspace_path, "agent_metadata.yaml")
    data = metadata.model_dump(exclude_none=True)
    with open(filepath, "w") as f:
        yaml.dump(data, f, default_flow_style=False, indent=2, sort_keys=False)
    return filepath

import logging
from typing import Optional, Dict, Any

from kubernetes import client, config
from kubernetes.client.rest import ApiException

logger = logging.getLogger(__name__)


class KubernetesProvider:
    def __init__(self, namespace: str = "default", verbose: bool = False, kubeconfig: Optional[str] = None):
        self.namespace = namespace
        self.verbose = verbose

        if kubeconfig:
            config.load_kube_config(config_file=kubeconfig)
        else:
            try:
                config.load_incluster_config()
            except:
                config.load_kube_config()

        self.apps_v1 = client.AppsV1Api()
        self.core_v1 = client.CoreV1Api()

    def deploy_agent(
        self,
        agent_name: str,
        image_url: str,
        port: int = 8080,
        entrypoint: Optional[str] = None,
        replicas: int = 1,
        node_port: Optional[int] = None,
        env_vars: Optional[Dict[str, str]] = None,
    ) -> Dict[str, Any]:
        labels = {"app": agent_name, "app.kubernetes.io/managed-by": "agentcube"}

        env_list = []
        if env_vars:
            for key, value in env_vars.items():
                env_list.append({"name": key, "value": value})

        container = client.V1Container(
            name=agent_name,
            image=image_url,
            ports=[client.V1ContainerPort(container_port=port)],
            env=env_list if env_list else None,
        )

        if entrypoint:
            container.command = ["/bin/sh", "-c", entrypoint]

        pod_spec = client.V1PodSpec(
            containers=[container],
            restart_policy="Always",
        )

        pod_template = client.V1PodTemplateSpec(
            metadata=client.V1ObjectMeta(labels=labels),
            spec=pod_spec,
        )

        deployment_spec = client.V1DeploymentSpec(
            replicas=replicas,
            selector=client.V1LabelSelector(match_labels=labels),
            template=pod_template,
        )

        deployment = client.V1Deployment(
            api_version="apps/v1",
            kind="Deployment",
            metadata=client.V1ObjectMeta(name=agent_name, labels=labels),
            spec=deployment_spec,
        )

        try:
            self.apps_v1.create_namespaced_deployment(namespace=self.namespace, body=deployment)
            logger.info(f"Created deployment {agent_name}")
        except ApiException as e:
            if e.status == 409:
                self.apps_v1.patch_namespaced_deployment(
                    name=agent_name, namespace=self.namespace, body=deployment
                )
                logger.info(f"Updated deployment {agent_name}")
            else:
                raise

        service_spec = client.V1ServiceSpec(
            selector=labels,
            ports=[client.V1ServicePort(port=port, target_port=port)],
            type="NodePort" if node_port else "ClusterIP",
        )

        service = client.V1Service(
            api_version="v1",
            kind="Service",
            metadata=client.V1ObjectMeta(name=agent_name),
            spec=service_spec,
        )

        try:
            self.core_v1.create_namespaced_service(namespace=self.namespace, body=service)
            logger.info(f"Created service {agent_name}")
        except ApiException as e:
            if e.status == 409:
                self.core_v1.patch_namespaced_service(
                    name=agent_name, namespace=self.namespace, body=service
                )
                logger.info(f"Updated service {agent_name}")
            else:
                raise

        return {"name": agent_name, "namespace": self.namespace}

    def wait_for_deployment_ready(self, name: str, timeout: int = 120) -> bool:
        import time
        start_time = time.time()

        while time.time() - start_time < timeout:
            try:
                deployment = self.apps_v1.read_namespaced_deployment(name=name, namespace=self.namespace)
                if deployment.status.ready_replicas == deployment.spec.replicas:
                    return True
            except ApiException:
                pass
            time.sleep(2)

        raise TimeoutError(f"Deployment {name} not ready after {timeout} seconds")

    def get_agent_status(self, agent_name: str) -> Dict[str, Any]:
        try:
            deployment = self.apps_v1.read_namespaced_deployment(name=agent_name, namespace=self.namespace)
            return {
                "name": agent_name,
                "namespace": self.namespace,
                "replicas": deployment.spec.replicas,
                "ready_replicas": deployment.status.ready_replicas or 0,
                "status": "running" if deployment.status.ready_replicas == deployment.spec.replicas else "pending",
            }
        except ApiException as e:
            if e.status == 404:
                return {"name": agent_name, "status": "not_found"}
            raise

    def delete_agent(self, agent_name: str) -> bool:
        try:
            self.apps_v1.delete_namespaced_deployment(name=agent_name, namespace=self.namespace)
            logger.info(f"Deleted deployment {agent_name}")
        except ApiException as e:
            if e.status != 404:
                raise

        try:
            self.core_v1.delete_namespaced_service(name=agent_name, namespace=self.namespace)
            logger.info(f"Deleted service {agent_name}")
        except ApiException as e:
            if e.status != 404:
                raise

        return True

import logging
import time
from typing import Optional, Dict, Any

import docker
from docker.errors import DockerException, BuildError, APIError


logger = logging.getLogger(__name__)


def check_docker_available() -> bool:
    try:
        client = docker.from_env()
        client.ping()
        return True
    except DockerException:
        return False


def build_image(
    dockerfile_path: str,
    context_path: str,
    image_name: str,
    tag: str = "latest",
    build_args: Optional[Dict[str, str]] = None,
) -> Dict[str, Any]:
    client = docker.from_env()

    full_image_name = f"{image_name}:{tag}"
    start_time = time.time()

    try:
        image, build_logs = client.images.build(
            path=context_path,
            dockerfile=dockerfile_path,
            tag=full_image_name,
            buildargs=build_args,
            rm=True,
        )

        build_time = time.time() - start_time

        return {
            "image_name": full_image_name,
            "image_id": image.id,
            "image_size": image.attrs.get("Size", 0),
            "build_time": build_time,
        }
    except BuildError as e:
        logger.error(f"Build failed: {e}")
        raise


def push_image(
    image_name: str,
    registry_url: Optional[str] = None,
    username: Optional[str] = None,
    password: Optional[str] = None,
) -> Dict[str, Any]:
    client = docker.from_env()

    if registry_url and username and password:
        client.login(username=username, password=password, registry=registry_url)

    if registry_url:
        parts = image_name.split("/", 1)
        if len(parts) == 1 or not parts[0].contains("."):
            image_name = f"{registry_url}/{image_name}"

    start_time = time.time()

    try:
        push_logs = client.images.push(image_name, stream=True, decode=True)
        for log in push_logs:
            if "error" in log:
                raise Exception(log["error"])
            logger.debug(log)

        push_time = time.time() - start_time

        return {
            "pushed_image": image_name,
            "push_time": push_time,
        }
    except APIError as e:
        logger.error(f"Push failed: {e}")
        raise


def remove_image(image_name: str) -> bool:
    try:
        client = docker.from_env()
        client.images.remove(image_name, force=True)
        return True
    except Exception as e:
        logger.warning(f"Failed to remove image {image_name}: {e}")
        return False

import os
import logging
from typing import Optional, Dict, Any

from ..services.metadata_service import load_metadata, save_metadata, AgentMetadata


logger = logging.getLogger(__name__)


class PackRuntime:
    def pack(
        self,
        workspace_path: str,
        agent_name: Optional[str] = None,
        language: str = "python",
        entrypoint: Optional[str] = None,
        port: int = 8080,
        build_mode: str = "local",
        description: Optional[str] = None,
        output: Optional[str] = None,
        verbose: bool = False,
    ) -> Dict[str, Any]:
        self._validate_workspace_structure(workspace_path, language)

        try:
            metadata = load_metadata(workspace_path)
        except FileNotFoundError:
            metadata = AgentMetadata(
                agent_name=agent_name or os.path.basename(os.path.abspath(workspace_path)),
                language=language,
                port=port,
                build_mode=build_mode,
            )

        if agent_name:
            metadata.agent_name = agent_name
        if entrypoint:
            metadata.entrypoint = entrypoint
        if description:
            metadata.description = description
        if port != 8080:
            metadata.port = port

        self._validate_language_compatibility(metadata.language)

        self._process_dependencies(workspace_path, metadata)

        dockerfile_content = self._generate_dockerfile(metadata, workspace_path)
        dockerfile_path = os.path.join(workspace_path, "Dockerfile")
        with open(dockerfile_path, "w") as f:
            f.write(dockerfile_content)

        output_path = output or workspace_path
        metadata_path = save_metadata(output_path, metadata)

        return {
            "agent_name": metadata.agent_name,
            "workspace_path": workspace_path,
            "metadata_path": metadata_path,
            "dockerfile_path": dockerfile_path,
        }

    def _validate_workspace_structure(self, workspace_path: str, language: str):
        if not os.path.exists(workspace_path):
            raise ValueError(f"Workspace path does not exist: {workspace_path}")
        if not os.path.isdir(workspace_path):
            raise ValueError(f"Workspace path is not a directory: {workspace_path}")

        if language.lower() == "python":
            py_files = [f for f in os.listdir(workspace_path) if f.endswith(".py")]
            if not py_files:
                raise ValueError("Python workspace requires at least one .py file")
        elif language.lower() == "java":
            pom_path = os.path.join(workspace_path, "pom.xml")
            if not os.path.exists(pom_path):
                raise ValueError("Java workspace requires pom.xml")

    def _validate_language_compatibility(self, language: str):
        supported = ["python", "java"]
        if language.lower() not in supported:
            raise ValueError(f"Unsupported language: {language}. Supported: {supported}")

    def _process_dependencies(self, workspace_path: str, metadata: AgentMetadata):
        if metadata.language == "python":
            req_path = os.path.join(workspace_path, "requirements.txt")
            if os.path.exists(req_path):
                metadata.requirements_file = "requirements.txt"

    def _generate_dockerfile(self, metadata: AgentMetadata, workspace_path: str) -> str:
        if metadata.language == "python":
            return self._generate_python_dockerfile(metadata)
        elif metadata.language == "java":
            return self._generate_java_dockerfile(metadata)
        return ""

    def _generate_python_dockerfile(self, metadata: AgentMetadata) -> str:
        dockerfile = f'''FROM python:3.12-slim

WORKDIR /app

'''
        if metadata.requirements_file:
            dockerfile += f'COPY {metadata.requirements_file} .\nRUN pip install --no-cache-dir -r {metadata.requirements_file}\n\n'

        dockerfile += 'COPY . .\n\n'

        if metadata.entrypoint:
            dockerfile += f'CMD {metadata.entrypoint}\n'
        else:
            py_files = [f for f in os.listdir('.') if f.endswith('.py') and f != '__init__.py']
            if py_files:
                dockerfile += f'CMD ["python", "{py_files[0]}"]\n'

        return dockerfile

    def _generate_java_dockerfile(self, metadata: AgentMetadata) -> str:
        return f'''FROM maven:3.9-eclipse-temurin-21 AS build
WORKDIR /app
COPY pom.xml .
RUN mvn dependency:go-offline

COPY src ./src
RUN mvn package -DskipTests

FROM eclipse-temurin:21-jre
WORKDIR /app
COPY --from=build /app/target/*.jar app.jar

EXPOSE {metadata.port}

CMD ["java", "-jar", "app.jar"]
'''

import os
import logging
from typing import Optional, Dict, Any

from ..services.metadata_service import load_metadata, save_metadata, AgentMetadata
from ..services.docker_service import check_docker_available, build_image


logger = logging.getLogger(__name__)


class BuildRuntime:
    def build(
        self,
        workspace_path: str,
        proxy: Optional[str] = None,
        cloud_provider: Optional[str] = None,
        output: Optional[str] = None,
        verbose: bool = False,
    ) -> Dict[str, Any]:
        metadata = load_metadata(workspace_path)

        if metadata.build_mode == "local":
            return self._build_local(workspace_path, metadata, proxy, verbose)
        elif metadata.build_mode == "cloud":
            return self._build_cloud(workspace_path, metadata, cloud_provider, verbose)
        else:
            raise ValueError(f"Unsupported build mode: {metadata.build_mode}")

    def _build_local(
        self,
        workspace_path: str,
        metadata: AgentMetadata,
        proxy: Optional[str],
        verbose: bool,
    ) -> Dict[str, Any]:
        if not check_docker_available():
            raise RuntimeError("Docker is not available. Please start Docker.")

        dockerfile_path = os.path.join(workspace_path, "Dockerfile")
        if not os.path.exists(dockerfile_path):
            raise FileNotFoundError(f"Dockerfile not found at {dockerfile_path}")

        original_version = metadata.version
        new_version = self._increment_version(metadata.version)
        metadata.version = new_version

        image_name = f"agentcube/{metadata.agent_name}"

        build_args = {}
        if proxy:
            build_args["HTTP_PROXY"] = proxy
            build_args["HTTPS_PROXY"] = proxy

        try:
            result = build_image(
                dockerfile_path=dockerfile_path,
                context_path=workspace_path,
                image_name=image_name,
                tag=new_version,
                build_args=build_args if build_args else None,
            )
            metadata.image_url = result["image_name"]
            save_metadata(workspace_path, metadata)
            return result
        except Exception as e:
            metadata.version = original_version
            save_metadata(workspace_path, metadata)
            raise

    def _build_cloud(
        self,
        workspace_path: str,
        metadata: AgentMetadata,
        cloud_provider: Optional[str],
        verbose: bool,
    ) -> Dict[str, Any]:
        raise NotImplementedError("Cloud build is not yet implemented")

    def _increment_version(self, version: str) -> str:
        parts = version.split(".")
        if len(parts) == 3:
            try:
                patch = int(parts[2]) + 1
                return f"{parts[0]}.{parts[1]}.{patch}"
            except ValueError:
                pass
        return f"{version}.1"

import json
import logging
from typing import Optional, Dict, Any

import httpx

from ..services.metadata_service import load_metadata


logger = logging.getLogger(__name__)


class InvokeRuntime:
    def invoke(
        self,
        workspace_path: str,
        payload: Dict[str, Any],
        headers: Dict[str, str],
        provider: str = "agentcube",
        verbose: bool = False,
    ) -> Any:
        metadata = load_metadata(workspace_path)

        router_url = metadata.router_url
        if not router_url:
            raise ValueError("router_url not set in metadata")

        if metadata.session_id:
            headers["X-Agentcube-Session-Id"] = metadata.session_id

        base_url = self._build_invoke_url(metadata, provider)

        return self._make_request(base_url, payload, headers, verbose)

    def _build_invoke_url(self, metadata, provider: str) -> str:
        router_url = metadata.router_url.rstrip("/")

        if provider == "agentcube":
            return f"{router_url}/v1/namespaces/default/agent-runtimes/{metadata.agent_name}/invocations/"
        else:
            return f"{router_url}/v1/namespaces/default/agent-runtimes/{metadata.agent_name}/invocations/"

    def _make_request(
        self,
        url: str,
        payload: Dict[str, Any],
        headers: Dict[str, str],
        verbose: bool,
    ) -> Any:
        if "Content-Type" not in headers:
            headers["Content-Type"] = "application/json"

        if verbose:
            logger.debug(f"POST {url}")
            logger.debug(f"Headers: {headers}")
            logger.debug(f"Payload: {json.dumps(payload, indent=2)}")

        with httpx.Client(timeout=120.0) as client:
            response = client.post(url, json=payload, headers=headers)
            response.raise_for_status()
            return response.json()

import logging
from typing import Dict, Any

from ..services.metadata_service import load_metadata


logger = logging.getLogger(__name__)


class StatusRuntime:
    def get_status(
        self,
        workspace_path: str,
        provider: str = "agentcube",
        verbose: bool = False,
    ) -> Dict[str, Any]:
        try:
            metadata = load_metadata(workspace_path)
        except FileNotFoundError:
            return {"status": "not_published", "message": "No metadata file found"}

        if provider == "agentcube":
            return self._get_cr_k8s_status(metadata, verbose)
        elif provider == "k8s":
            return self._get_k8s_status(metadata, verbose)
        else:
            raise ValueError(f"Unsupported provider: {provider}")

    def _get_cr_k8s_status(self, metadata, verbose: bool) -> Dict[str, Any]:
        from ..services.agentcube_provider import AgentcubeProvider

        try:
            provider = AgentcubeProvider(verbose=verbose)
            cr = provider.get_agent_runtime(metadata.agent_name, "default")

            if not cr:
                return {
                    "status": "not_published",
                    "agent_name": metadata.agent_name,
                }

            status = cr.get("status", {})
            return {
                "status": "published",
                "agent_name": metadata.agent_name,
                "conditions": status.get("conditions", []),
            }
        except Exception as e:
            logger.warning(f"Failed to get CR status: {e}")
            return {
                "status": "error",
                "agent_name": metadata.agent_name,
                "error": str(e),
            }

    def _get_k8s_status(self, metadata, verbose: bool) -> Dict[str, Any]:
        from ..services.k8s_provider import KubernetesProvider

        try:
            provider = KubernetesProvider(verbose=verbose)
            return provider.get_agent_status(metadata.agent_name)
        except Exception as e:
            logger.warning(f"Failed to get K8s status: {e}")
            return {
                "status": "error",
                "agent_name": metadata.agent_name,
                "error": str(e),
            }

import logging
from typing import Optional, Dict, Any

from kubernetes import client, config
from kubernetes.client.rest import ApiException


logger = logging.getLogger(__name__)


class AgentcubeProvider:
    API_GROUP = "runtime.agentcube.volcano.sh"
    API_VERSION = "v1alpha1"

    def __init__(self, namespace: str = "default", verbose: bool = False, kubeconfig: Optional[str] = None):
        self.namespace = namespace
        self.verbose = verbose

        if kubeconfig:
            config.load_kube_config(config_file=kubeconfig)
        else:
            try:
                config.load_incluster_config()
            except:
                config.load_kube_config()

        self.custom_api = client.CustomObjectsApi()

    def deploy_agent_runtime(
        self,
        agent_name: str,
        image_url: str,
        port: int = 8080,
        entrypoint: Optional[str] = None,
        env_vars: Optional[Dict[str, str]] = None,
        workload_manager_url: Optional[str] = None,
        router_url: Optional[str] = None,
        readiness_probe_path: Optional[str] = None,
        readiness_probe_port: int = 8080,
    ) -> Dict[str, Any]:
        body = {
            "apiVersion": f"{self.API_GROUP}/{self.API_VERSION}",
            "kind": "AgentRuntime",
            "metadata": {
                "name": agent_name,
                "namespace": self.namespace,
            },
            "spec": {
                "targetPort": [{"port": port, "protocol": "HTTP"}],
                "podTemplate": {
                    "spec": {
                        "containers": [
                            {
                                "name": agent_name,
                                "image": image_url,
                                "ports": [{"containerPort": port}],
                            }
                        ]
                    }
                },
                "sessionTimeout": "15m",
                "maxSessionDuration": "8h",
            },
        }

        if env_vars:
            body["spec"]["podTemplate"]["spec"]["containers"][0]["env"] = [
                {"name": k, "value": v} for k, v in env_vars.items()
            ]

        try:
            self.custom_api.create_namespaced_custom_object(
                group=self.API_GROUP,
                version=self.API_VERSION,
                namespace=self.namespace,
                plural="agentruntimes",
                body=body,
            )
            logger.info(f"Created AgentRuntime {agent_name}")
        except ApiException as e:
            if e.status == 409:
                self.custom_api.patch_namespaced_custom_object(
                    group=self.API_GROUP,
                    version=self.API_VERSION,
                    namespace=self.namespace,
                    plural="agentruntimes",
                    name=agent_name,
                    body=body,
                )
                logger.info(f"Updated AgentRuntime {agent_name}")
            else:
                raise

        return {"name": agent_name, "namespace": self.namespace}

    def get_agent_runtime(self, name: str, namespace: str) -> Optional[Dict[str, Any]]:
        try:
            return self.custom_api.get_namespaced_custom_object(
                group=self.API_GROUP,
                version=self.API_VERSION,
                namespace=namespace,
                plural="agentruntimes",
                name=name,
            )
        except ApiException as e:
            if e.status == 404:
                return None
            raise
